import 'package:flutter/material.dart';

class LoginForm extends StatefulWidget {
  const LoginForm({super.key});
  @override State<LoginForm> createState() => _LoginFormState();
}

class _LoginFormState extends State<LoginForm> {
  final _formKey = GlobalKey<FormState>();

  // Controllers = mutable source of truth for text.
  final _email = TextEditingController();
  final _password = TextEditingController();

  // Focus nodes = programmatic focus (next-button flow).
  final _emailFocus = FocusNode();
  final _pwFocus = FocusNode();

  bool _obscure = true;

  @override
  void dispose() {
    _email.dispose();
    _password.dispose();
    _emailFocus.dispose();
    _pwFocus.dispose();
    super.dispose();
  }

  void _submit() {
    if (!_formKey.currentState!.validate()) return;
    debugPrint('valid! email=${_email.text}');
    // ... call your API
  }

  @override
  Widget build(BuildContext context) => Form(
    key: _formKey,
    // Reactive validation — errors appear as the user types (after first submit)
    autovalidateMode: AutovalidateMode.onUserInteraction,
    child: Column(
      children: [
        TextFormField(
          controller: _email,
          focusNode: _emailFocus,
          keyboardType: TextInputType.emailAddress,
          textInputAction: TextInputAction.next,
          decoration: const InputDecoration(labelText: 'Email'),
          validator: (v) {
            if (v == null || v.isEmpty) return 'Required';
            if (!v.contains('@')) return 'Must be a valid email';
            return null;
          },
          onFieldSubmitted: (_) => _pwFocus.requestFocus(),
        ),
        TextFormField(
          controller: _password,
          focusNode: _pwFocus,
          obscureText: _obscure,
          textInputAction: TextInputAction.done,
          decoration: InputDecoration(
            labelText: 'Password',
            suffixIcon: IconButton(
              icon: Icon(_obscure ? Icons.visibility : Icons.visibility_off),
              onPressed: () => setState(() => _obscure = !_obscure),
            ),
          ),
          validator: (v) => v == null || v.length < 6 ? 'Min 6 characters' : null,
          onFieldSubmitted: (_) => _submit(),
        ),
        const SizedBox(height: 16),
        FilledButton(onPressed: _submit, child: const Text('Sign in')),
      ],
    ),
  );
}

// Notice: EVERY controller and focus node created in initState (via `final`
// field init) is DISPOSED in dispose(). Miss any of them = leak.
